// 어제 00:00 ~ 23:59:59 (KST 기준)
const now = new Date();
const yesterday = new Date(now);
yesterday.setDate(yesterday.getDate() - 1);
yesterday.setHours(0, 0, 0, 0);

const yesterdayEnd = new Date(yesterday);
yesterdayEnd.setHours(23, 59, 59, 999);

return {
  fromISO: yesterday.toISOString(),
  toISO: yesterdayEnd.toISOString(),
  reportDate: yesterday.toISOString().split('T')[0]
};

const items = $input.all();
const sellersResponse = items[0]?.json;
const executionsResponse = items[1]?.json;

const sellers = sellersResponse?.data?.content || [];
const executions = executionsResponse?.data?.content || [];

// Seller ID → Name 매핑
const sellerMap = {};
sellers.forEach(s => {
  sellerMap[s.sellerId] = s.sellerName || s.mustItSellerName || `Seller ${s.sellerId}`;
});

// Seller별 통계 집계
const sellerStats = {};

sellers.forEach(s => {
  sellerStats[s.sellerId] = {
    sellerId: s.sellerId,
    sellerName: sellerMap[s.sellerId],
    status: s.status,
    productCount: s.productCount || 0,
    success: 0,
    failed: 0,
    timeout: 0,
    running: 0,
    totalDurationMs: 0,
    executionCount: 0
  };
});

executions.forEach(exec => {
  const sellerId = exec.sellerId;
  if (!sellerStats[sellerId]) {
    sellerStats[sellerId] = {
      sellerId,
      sellerName: `Unknown (${sellerId})`,
      status: 'UNKNOWN',
      productCount: 0,
      success: 0,
      failed: 0,
      timeout: 0,
      running: 0,
      totalDurationMs: 0,
      executionCount: 0
    };
  }

  const stats = sellerStats[sellerId];
  stats.executionCount++;

  switch (exec.status) {
    case 'SUCCESS': stats.success++; break;
    case 'FAILED': stats.failed++; break;
    case 'TIMEOUT': stats.timeout++; break;
    case 'RUNNING': stats.running++; break;
  }

  if (exec.durationMs) {
    stats.totalDurationMs += exec.durationMs;
  }
});

// 결과 정리
const sellerReports = Object.values(sellerStats)
  .map(s => {
    const total = s.success + s.failed + s.timeout;
    const successRate = total > 0 ? (s.success / total * 100).toFixed(1) : 'N/A';
    const avgDuration = s.executionCount > 0 
      ? (s.totalDurationMs / s.executionCount / 1000).toFixed(2) 
      : 'N/A';

    return {
      ...s,
      totalExecutions: total,
      successRate,
      avgDurationSec: avgDuration
    };
  })
  .filter(s => s.totalExecutions > 0 || s.status === 'ACTIVE')
  .sort((a, b) => b.totalExecutions - a.totalExecutions);

// 전체 요약
const totalSuccess = sellerReports.reduce((sum, s) => sum + s.success, 0);
const totalFailed = sellerReports.reduce((sum, s) => sum + s.failed, 0);
const totalTimeout = sellerReports.reduce((sum, s) => sum + s.timeout, 0);
const totalExecutions = totalSuccess + totalFailed + totalTimeout;
const overallSuccessRate = totalExecutions > 0 
  ? (totalSuccess / totalExecutions * 100).toFixed(1) 
  : 'N/A';

// Top 5 성공률 Seller
const topSellers = sellerReports
  .filter(s => s.totalExecutions >= 10)
  .sort((a, b) => parseFloat(b.successRate) - parseFloat(a.successRate))
  .slice(0, 5);

// 문제 Seller (실패율 20% 이상)
const problematicSellers = sellerReports
  .filter(s => s.totalExecutions >= 5 && parseFloat(s.successRate) < 80)
  .sort((a, b) => parseFloat(a.successRate) - parseFloat(b.successRate))
  .slice(0, 5);

// 비활성 Seller (ACTIVE인데 실행 없음)
const inactiveSellers = sellerReports
  .filter(s => s.status === 'ACTIVE' && s.totalExecutions === 0);

const reportDate = $('Calculate Yesterday Range').item.json.reportDate;

return {
  reportDate,
  summary: {
    totalSellers: sellers.length,
    activeSellers: sellers.filter(s => s.status === 'ACTIVE').length,
    totalExecutions,
    totalSuccess,
    totalFailed,
    totalTimeout,
    overallSuccessRate
  },
  topSellers,
  problematicSellers,
  inactiveSellers: inactiveSellers.slice(0, 5),
  sellerReports: sellerReports.slice(0, 20)
};

const data = $input.first().json;
const summary = data.summary;
const topSellers = data.topSellers;
const problematicSellers = data.problematicSellers;
const inactiveSellers = data.inactiveSellers;

// Top Sellers 텍스트
let topSellersText = topSellers.length > 0
  ? topSellers.map((s, i) => `${i + 1}. ${s.sellerName}: ${s.successRate}% (${s.totalExecutions}건)`).join('\n')
  : '해당 없음';

// 문제 Sellers 텍스트
let problemText = problematicSellers.length > 0
  ? problematicSellers.map(s => `• ${s.sellerName}: ${s.successRate}% (실패 ${s.failed + s.timeout}건)`).join('\n')
  : '✅ 모든 Seller 정상';

// 비활성 Sellers 텍스트
let inactiveText = inactiveSellers.length > 0
  ? inactiveSellers.map(s => `• ${s.sellerName}`).join('\n')
  : '해당 없음';

const slackMessage = {
  text: `📊 CrawlingHub Daily Report - ${data.reportDate}`,
  attachments: [
    {
      color: '#36a64f',
      blocks: [
        {
          type: 'header',
          text: {
            type: 'plain_text',
            text: `📊 CrawlingHub 일간 리포트 - ${data.reportDate}`,
            emoji: true
          }
        },
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: '*📈 전체 요약*'
          }
        },
        {
          type: 'section',
          fields: [
            {
              type: 'mrkdwn',
              text: `*총 Seller*\n${summary.totalSellers}개 (Active: ${summary.activeSellers})`
            },
            {
              type: 'mrkdwn',
              text: `*총 크롤링*\n${summary.totalExecutions}건`
            },
            {
              type: 'mrkdwn',
              text: `*전체 성공률*\n${summary.overallSuccessRate}%`
            },
            {
              type: 'mrkdwn',
              text: `*성공/실패/타임아웃*\n${summary.totalSuccess}/${summary.totalFailed}/${summary.totalTimeout}`
            }
          ]
        },
        {
          type: 'divider'
        },
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: `*🏆 Top 5 Seller (성공률)*\n${topSellersText}`
          }
        },
        {
          type: 'divider'
        },
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: `*⚠️ 주의 필요 Seller (성공률 80% 미만)*\n${problemText}`
          }
        },
        {
          type: 'divider'
        },
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: `*💤 비활성 Seller (ACTIVE이나 크롤링 없음)*\n${inactiveText}`
          }
        },
        {
          type: 'context',
          elements: [
            {
              type: 'mrkdwn',
              text: `⏰ 리포트 생성: ${new Date().toISOString()}`
            }
          ]
        }
      ]
    }
  ]
};

return { slackMessage };
